import React, { useState } from 'react';

const ROWS = 6;
const COLS = 7;
const DIRS = [
  [0, 1],
  [1, 0],
  [1, 1],
  [1, -1],
];

const empty = () => Array.from({ length: ROWS }, () => Array(COLS).fill(null));

function findWin(g, r, c, p) {
  for (const [dr, dc] of DIRS) {
    let n = 0;
    for (let k = -3; k <= 3; k++) {
      const rr = r + dr * k;
      const cc = c + dc * k;
      if (rr >= 0 && rr < ROWS && cc >= 0 && cc < COLS && g[rr][cc] === p) {
        n++;
        if (n >= 4) return true;
      } else {
        n = 0;
      }
    }
  }
  return false;
}

export default function ConnectFour() {
  const [grid, setGrid] = useState(empty);
  const [red, setRed] = useState(true);
  const [winner, setWinner] = useState(null);

  const drop = (col) => {
    if (winner) return;
    let row = -1;
    for (let r = ROWS - 1; r >= 0; r--) {
      if (!grid[r][col]) {
        row = r;
        break;
      }
    }
    if (row === -1) return;
    const p = red ? 'R' : 'Y';
    const next = grid.map((rw) => rw.slice());
    next[row][col] = p;
    setGrid(next);
    if (findWin(next, row, col, p)) setWinner(p);
    else setRed(!red);
  };

  const reset = () => {
    setGrid(empty());
    setRed(true);
    setWinner(null);
  };

  const status = winner
    ? `${winner === 'R' ? 'Red' : 'Yellow'} wins!`
    : `${red ? 'Red' : 'Yellow'} to move`;

  return (
    <div>
      <p style={{ fontWeight: 600, fontSize: 18 }}>{status}</p>
      <div style={{ display: 'inline-block', background: '#1d4ed8', padding: 8, borderRadius: 10 }}>
        {grid.map((row, r) => (
          <div key={r} style={{ display: 'flex' }}>
            {row.map((cell, c) => (
              <div
                key={c}
                onClick={() => drop(c)}
                style={{ width: 44, height: 44, margin: 3, borderRadius: '50%', cursor: 'pointer', background: cell === 'R' ? '#dc2626' : cell === 'Y' ? '#facc15' : '#dbeafe' }}
              />
            ))}
          </div>
        ))}
      </div>
      <div>
        <button onClick={reset} style={{ marginTop: 14, padding: '8px 16px', cursor: 'pointer' }}>Reset</button>
      </div>
    </div>
  );
}

