import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-connect-four',
  template: `
    <div>
      <p style="font-weight: 600; font-size: 18px;">{{ status }}</p>
      <div style="display: inline-block; background: #1d4ed8; padding: 8px; border-radius: 10px;">
        <div *ngFor="let row of grid; let r = index" style="display: flex;">
          <div
            *ngFor="let cell of row; let c = index"
            (click)="drop(c)"
            [style.background]="colorOf(cell)"
            style="width: 44px; height: 44px; margin: 3px; border-radius: 50%; cursor: pointer;"
          ></div>
        </div>
      </div>
      <div>
        <button (click)="reset()" style="margin-top: 14px; padding: 8px 16px; cursor: pointer;">Reset</button>
      </div>
    </div>
  `,
})
export class ConnectFourComponent {
  readonly ROWS = 6;
  readonly COLS = 7;
  readonly DIRS = [
    [0, 1],
    [1, 0],
    [1, 1],
    [1, -1],
  ];

  grid: (string | null)[][] = this.empty();
  red = true;
  winner: string | null = null;

  empty(): (string | null)[][] {
    return Array.from({ length: 6 }, () => Array(7).fill(null));
  }

  colorOf(cell: string | null): string {
    if (cell === 'R') return '#dc2626';
    if (cell === 'Y') return '#facc15';
    return '#dbeafe';
  }

  findWin(g: (string | null)[][], r: number, c: number, p: string): boolean {
    for (const [dr, dc] of this.DIRS) {
      let n = 0;
      for (let k = -3; k <= 3; k++) {
        const rr = r + dr * k;
        const cc = c + dc * k;
        if (rr >= 0 && rr < this.ROWS && cc >= 0 && cc < this.COLS && g[rr][cc] === p) {
          n++;
          if (n >= 4) {
            return true;
          }
        } else {
          n = 0;
        }
      }
    }
    return false;
  }

  drop(col: number): void {
    if (this.winner) {
      return;
    }
    let row = -1;
    for (let r = this.ROWS - 1; r >= 0; r--) {
      if (!this.grid[r][col]) {
        row = r;
        break;
      }
    }
    if (row === -1) {
      return;
    }
    const p = this.red ? 'R' : 'Y';
    const next = this.grid.map((rw) => rw.slice());
    next[row][col] = p;
    this.grid = next;
    if (this.findWin(next, row, col, p)) {
      this.winner = p;
    } else {
      this.red = !this.red;
    }
  }

  reset(): void {
    this.grid = this.empty();
    this.red = true;
    this.winner = null;
  }

  get status(): string {
    if (this.winner) {
      return (this.winner === 'R' ? 'Red' : 'Yellow') + ' wins!';
    }
    return (this.red ? 'Red' : 'Yellow') + ' to move';
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Connect Four Demo</h1>
      <app-connect-four></app-connect-four>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, ConnectFourComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
